//
//  ProfileProView.swift (Settings Tab)
//  FitToday
//
//  Redesigned on 23/01/26 - New Settings layout with Premium and Apple Health
//

import RevenueCat
import SwiftData
import SwiftUI
import Swinject

struct ProfileProView: View {
    @Environment(\.dependencyResolver) private var resolver
    @Environment(AppRouter.self) private var router
    @AppStorage(AppStorageKeys.themePreference) private var themePreferenceRaw: String = ThemePreference.dark.rawValue
    @State private var entitlement: ProEntitlement = .free
    @State private var showingPaywall = false
    @State private var showingRestoreAlert = false
    @State private var restoreMessage = ""
    @State private var userName: String = "Athlete"
    @State private var userProfile: UserProfile?
    @State private var streakDays: Int = 0
    @State private var totalMinutes: Int = 0
    @State private var completedWorkouts: Int = 0
    @State private var isPersonalTrainerEnabled = false

    #if DEBUG
    @State private var debugModeEnabled = false
    @State private var debugIsPro = false
    #endif

    private var entitlementRepository: EntitlementRepository? {
        resolver.resolve(EntitlementRepository.self)
    }


    var body: some View {
        ScrollView {
            VStack(spacing: FitTodaySpacing.lg) {
                // User Profile Header
                ProfileHeaderSection(name: userName)

                // Stats Row
                ProfileStatsRow(
                    streak: streakDays,
                    totalMinutes: totalMinutes,
                    completedWorkouts: completedWorkouts
                )

                // Premium Card
                premiumCard

                // Apple Health Integration
                appleHealthCard

                // Personal Trainer
                if isPersonalTrainerEnabled {
                    personalTrainerCard
                }

                // Training Profile
                trainingProfileSection

                // Profile Settings
                settingsSection

                // Account
                accountSection

                #if DEBUG
                DebugSection(
                    debugModeEnabled: $debugModeEnabled,
                    debugIsPro: $debugIsPro,
                    showingRestoreAlert: $showingRestoreAlert,
                    restoreMessage: $restoreMessage,
                    resolver: resolver,
                    onDebugModeChange: handleDebugModeChange,
                    onDebugProChange: handleDebugProChange
                )
                #endif

                AppInfoFooter()
            }
            .padding()
            .padding(.bottom, FitTodaySpacing.xl)
        }
        .background(FitTodayColor.background.ignoresSafeArea())
        .toolbar(.hidden, for: .navigationBar)
        .task {
            await loadEntitlement()
            await loadProfileData()
            if let featureFlags = resolver.resolve(FeatureFlagChecking.self) {
                isPersonalTrainerEnabled = await featureFlags.isFeatureEnabled(.personalTrainerEnabled)
            }
        }
        .sheet(isPresented: $showingPaywall) {
            paywallSheet
        }
        .alert("Restore Purchases", isPresented: $showingRestoreAlert) {
            Button("Ok", role: .cancel) {}
        } message: {
            Text(restoreMessage)
        }
    }

    // MARK: - Header

    private var headerSection: some View {
        VStack(alignment: .leading, spacing: 4) {
            Text("settings.title".localized)
                .font(.system(size: 28, weight: .bold))
                .foregroundStyle(FitTodayColor.textPrimary)
            Text("settings.subtitle".localized)
                .font(.system(size: 14))
                .foregroundStyle(FitTodayColor.textSecondary)
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .padding(.top, FitTodaySpacing.md)
    }

    // MARK: - Premium Card

    private var premiumCard: some View {
        VStack(alignment: .leading, spacing: FitTodaySpacing.md) {
            // Badge
            HStack {
                HStack(spacing: 6) {
                    Image(systemName: entitlement.isPro ? "crown.fill" : "sparkles")
                        .font(.system(size: 12, weight: .semibold))
                    Text(entitlement.isPro ? "settings.pro.member".localized : "settings.pro.free".localized)
                        .font(.system(size: 11, weight: .semibold))
                }
                .foregroundStyle(.white)
                .padding(.horizontal, 10)
                .padding(.vertical, 4)
                .background(entitlement.isPro ? FitTodayColor.success : FitTodayColor.brandPrimary)
                .clipShape(Capsule())

                Spacer()
            }

            if entitlement.isPro {
                // Pro content
                Text("settings.pro.title".localized)
                    .font(.system(size: 20, weight: .bold))
                    .foregroundStyle(FitTodayColor.textPrimary)

                Text("settings.pro.access_all".localized)
                    .font(.system(size: 14))
                    .foregroundStyle(FitTodayColor.textSecondary)

                // Active features status
                HStack(spacing: FitTodaySpacing.md) {
                    syncStatusItem(icon: "heart.fill", label: "settings.pro.apple_health".localized, isActive: true)
                    syncStatusItem(icon: "bolt.fill", label: "settings.pro.ai_workouts".localized, isActive: true)
                }
                .padding(.top, 4)

                HStack(spacing: 6) {
                    Image(systemName: "checkmark.seal.fill")
                        .font(.system(size: 12, weight: .semibold))
                    Text("settings.pro.subscription_active".localized)
                        .font(.system(size: 14, weight: .semibold))
                }
                .foregroundStyle(FitTodayColor.success)
                .frame(maxWidth: .infinity)
                .padding(.vertical, 12)
                .background(FitTodayColor.success.opacity(0.15))
                .clipShape(RoundedRectangle(cornerRadius: 12))
            } else {
                // Free plan upgrade prompt
                Text("settings.pro.upgrade".localized)
                    .font(.system(size: 20, weight: .bold))
                    .foregroundStyle(FitTodayColor.textPrimary)

                Text("settings.pro.unlock_description".localized)
                    .font(.system(size: 14))
                    .foregroundStyle(FitTodayColor.textSecondary)

                // Features preview
                VStack(alignment: .leading, spacing: 8) {
                    featureItem(icon: "sparkles", text: "settings.pro.unlimited_ai".localized)
                    featureItem(icon: "chart.bar.fill", text: "settings.pro.advanced_charts".localized)
                    featureItem(icon: "heart.fill", text: "settings.pro.health_integration".localized)
                }
                .padding(.top, 4)

                Button {
                    showingPaywall = true
                } label: {
                    HStack {
                        Spacer()
                        Text("settings.pro.unlock".localized)
                            .font(.system(size: 14, weight: .semibold))
                        Image(systemName: "arrow.right")
                            .font(.system(size: 12, weight: .semibold))
                        Spacer()
                    }
                    .foregroundStyle(.white)
                    .padding(.vertical, 12)
                    .background(FitTodayColor.gradientPrimary)
                    .clipShape(RoundedRectangle(cornerRadius: 12))
                }
                .buttonStyle(.plain)
            }
        }
        .padding(FitTodaySpacing.lg)
        .background(FitTodayColor.surface)
        .clipShape(RoundedRectangle(cornerRadius: 20))
    }

    private func syncStatusItem(icon: String, label: String, isActive: Bool) -> some View {
        VStack(spacing: 4) {
            Image(systemName: icon)
                .font(.system(size: 16))
                .foregroundStyle(isActive ? FitTodayColor.success : FitTodayColor.textTertiary)
            Text(label)
                .font(.system(size: 10, weight: .medium))
                .foregroundStyle(FitTodayColor.textSecondary)
        }
        .frame(maxWidth: .infinity)
    }

    private func featureItem(icon: String, text: String) -> some View {
        HStack(spacing: 10) {
            Image(systemName: icon)
                .font(.system(size: 14))
                .foregroundStyle(FitTodayColor.brandPrimary)
                .frame(width: 20)
            Text(text)
                .font(.system(size: 13))
                .foregroundStyle(FitTodayColor.textPrimary)
        }
    }

    // MARK: - Apple Health Card

    private var appleHealthCard: some View {
        Button {
            router.push(.healthKitSettings, on: .profile)
        } label: {
            HStack(spacing: FitTodaySpacing.md) {
                ZStack {
                    RoundedRectangle(cornerRadius: 12)
                        .fill(Color(hex: "#FF2D55").opacity(0.15))
                        .frame(width: 44, height: 44)
                    Image(systemName: "heart.fill")
                        .font(.system(size: 20))
                        .foregroundStyle(Color(hex: "#FF2D55"))
                }

                VStack(alignment: .leading, spacing: 2) {
                    Text("settings.pro.apple_health".localized)
                        .font(.system(size: 16, weight: .semibold))
                        .foregroundStyle(FitTodayColor.textPrimary)
                    Text(entitlement.isPro ? "settings.pro.connected".localized : "settings.pro.connect_sync".localized)
                        .font(.system(size: 13))
                        .foregroundStyle(FitTodayColor.textSecondary)
                }

                Spacer()

                if entitlement.isPro {
                    Image(systemName: "checkmark.circle.fill")
                        .font(.system(size: 20))
                        .foregroundStyle(FitTodayColor.success)
                } else {
                    Text("PRO")
                        .font(.system(size: 10, weight: .bold))
                        .foregroundStyle(.white)
                        .padding(.horizontal, 8)
                        .padding(.vertical, 4)
                        .background(FitTodayColor.brandPrimary)
                        .clipShape(Capsule())
                }

                Image(systemName: "chevron.right")
                    .font(.system(size: 14))
                    .foregroundStyle(FitTodayColor.textTertiary)
            }
            .padding(FitTodaySpacing.md)
            .background(FitTodayColor.surface)
            .clipShape(RoundedRectangle(cornerRadius: 16))
        }
        .buttonStyle(.plain)
    }

    // MARK: - Personal Trainer Card

    private var personalTrainerCard: some View {
        Button {
            router.push(.personalTrainer, on: .profile)
        } label: {
            HStack(spacing: FitTodaySpacing.md) {
                ZStack {
                    RoundedRectangle(cornerRadius: 12)
                        .fill(FitTodayColor.brandPrimary.opacity(0.15))
                        .frame(width: 44, height: 44)
                    Image(systemName: "figure.strengthtraining.traditional")
                        .font(.system(size: 20))
                        .foregroundStyle(FitTodayColor.brandPrimary)
                }

                VStack(alignment: .leading, spacing: 2) {
                    Text("settings.personal_trainer".localized)
                        .font(.system(size: 16, weight: .semibold))
                        .foregroundStyle(FitTodayColor.textPrimary)
                    Text("settings.personal_trainer_desc".localized)
                        .font(.system(size: 13))
                        .foregroundStyle(FitTodayColor.textSecondary)
                }

                Spacer()

                Image(systemName: "chevron.right")
                    .font(.system(size: 14))
                    .foregroundStyle(FitTodayColor.textTertiary)
            }
            .padding(FitTodaySpacing.md)
            .background(FitTodayColor.surface)
            .clipShape(RoundedRectangle(cornerRadius: 16))
        }
        .buttonStyle(.plain)
    }

    // MARK: - Training Profile Section

    private var trainingProfileSection: some View {
        VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
            Text("Perfil de Treino")
                .font(.system(size: 13, weight: .semibold))
                .foregroundStyle(FitTodayColor.textSecondary)
                .padding(.leading, 4)

            Button {
                router.push(.editProfile, on: .profile)
            } label: {
                VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
                    HStack {
                        Text("Preferências de Treino")
                            .font(.system(.body, weight: .semibold))
                            .foregroundStyle(FitTodayColor.textPrimary)
                        Spacer()
                        Text("Editar")
                            .font(.system(size: 14, weight: .medium))
                            .foregroundStyle(FitTodayColor.brandPrimary)
                    }

                    if let profile = userProfile {
                        HStack(spacing: FitTodaySpacing.sm) {
                            profileChip(profile.mainGoal.title)
                            profileChip(profile.level.title)
                            profileChip("\(profile.weeklyFrequency)x/sem")
                        }
                    } else {
                        Text("Perfil incompleto")
                            .font(.system(size: 13))
                            .foregroundStyle(FitTodayColor.brandAccent)
                    }
                }
                .padding(FitTodaySpacing.md)
                .background(FitTodayColor.surface)
                .clipShape(RoundedRectangle(cornerRadius: 16))
            }
            .buttonStyle(.plain)
        }
    }

    private func profileChip(_ label: String) -> some View {
        Text(label)
            .font(.system(size: 12, weight: .medium))
            .foregroundStyle(FitTodayColor.textSecondary)
            .padding(.horizontal, FitTodaySpacing.sm)
            .padding(.vertical, 4)
            .background(FitTodayColor.backgroundElevated)
            .clipShape(Capsule())
    }

    // MARK: - Settings Section

    private var settingsSection: some View {
        VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
            Text("settings.profile".localized)
                .font(.system(size: 13, weight: .semibold))
                .foregroundStyle(FitTodayColor.textSecondary)
                .padding(.leading, 4)

            VStack(spacing: 0) {
                SettingsRow(icon: "person.text.rectangle", title: "settings.edit_profile".localized) {
                    router.push(.editProfile, on: .profile)
                }

                Divider().padding(.leading, 56)

                SettingsRow(icon: "lock.shield", title: "settings.privacy_settings".localized) {
                    router.push(.privacySettings, on: .profile)
                }

                Divider().padding(.leading, 56)

                languageRow

                Divider().padding(.leading, 56)

                themeRow
            }
            .background(FitTodayColor.surface)
            .clipShape(RoundedRectangle(cornerRadius: 16))
        }
    }

    // MARK: - Theme Row

    private var themeRow: some View {
        let selected = ThemePreference(rawValue: themePreferenceRaw) ?? .dark
        return HStack(spacing: FitTodaySpacing.md) {
            ZStack {
                RoundedRectangle(cornerRadius: 8)
                    .fill(FitTodayColor.brandPrimary.opacity(0.15))
                    .frame(width: 36, height: 36)
                Image(systemName: selected.icon)
                    .font(.system(size: 16))
                    .foregroundStyle(FitTodayColor.brandPrimary)
            }

            Text("settings.theme".localized)
                .font(.system(.body))
                .foregroundStyle(FitTodayColor.textPrimary)

            Spacer()

            Menu {
                ForEach(ThemePreference.allCases) { theme in
                    Button {
                        themePreferenceRaw = theme.rawValue
                    } label: {
                        HStack {
                            Image(systemName: theme.icon)
                            Text(theme.localizationKey.localized)
                            if selected == theme {
                                Image(systemName: "checkmark")
                            }
                        }
                    }
                }
            } label: {
                HStack(spacing: 4) {
                    Text(selected.localizationKey.localized)
                        .font(.system(size: 14))
                        .foregroundStyle(FitTodayColor.textSecondary)
                    Image(systemName: "chevron.up.chevron.down")
                        .font(.system(size: 10))
                        .foregroundStyle(FitTodayColor.textTertiary)
                }
            }
        }
        .padding(.horizontal, FitTodaySpacing.md)
        .padding(.vertical, FitTodaySpacing.sm)
    }

    // MARK: - Language Row

    @MainActor
    private var languageRow: some View {
        let manager = LocalizationManager.shared
        return HStack(spacing: FitTodaySpacing.md) {
            ZStack {
                RoundedRectangle(cornerRadius: 8)
                    .fill(FitTodayColor.brandPrimary.opacity(0.15))
                    .frame(width: 36, height: 36)
                Image(systemName: "globe")
                    .font(.system(size: 16))
                    .foregroundStyle(FitTodayColor.brandPrimary)
            }

            Text("settings.language".localized)
                .font(.system(.body))
                .foregroundStyle(FitTodayColor.textPrimary)

            Spacer()

            Menu {
                ForEach(LocalizationManager.Language.allCases) { language in
                    Button {
                        manager.setLanguage(language)
                    } label: {
                        HStack {
                            Text(language.displayName)
                            if manager.selectedLanguage == language {
                                Image(systemName: "checkmark")
                            }
                        }
                    }
                }
            } label: {
                HStack(spacing: 4) {
                    Text(manager.selectedLanguage.displayName)
                        .font(.system(size: 14))
                        .foregroundStyle(FitTodayColor.textSecondary)
                    Image(systemName: "chevron.up.chevron.down")
                        .font(.system(size: 10))
                        .foregroundStyle(FitTodayColor.textTertiary)
                }
            }
        }
        .padding(.horizontal, FitTodaySpacing.md)
        .padding(.vertical, FitTodaySpacing.sm)
    }

    // MARK: - Account Section

    private var accountSection: some View {
        VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
            Text("settings.account".localized)
                .font(.system(size: 13, weight: .semibold))
                .foregroundStyle(FitTodayColor.textSecondary)
                .padding(.leading, 4)

            VStack(spacing: 0) {
