//
//  CMSPersonalTrainerRepository.swift
//  FitToday
//
//  CMS-backed implementation of PersonalTrainerRepository.
//  Fetches trainers from the CMS API instead of Firebase.
//

import Foundation

final class CMSPersonalTrainerRepository: PersonalTrainerRepository, @unchecked Sendable {

    private let service: CMSTrainerService

    init(service: CMSTrainerService) {
        self.service = service
    }

    func fetchTrainer(id: String) async throws -> PersonalTrainer {
        let dto = try await service.fetchTrainer(id: id)
        return CMSTrainerMapper.toDomain(dto)
    }

    func searchTrainers(query: String, limit: Int) async throws -> [PersonalTrainer] {
        let response = try await service.fetchTrainers(limit: limit, offset: 0)
        // Sort: trainers with photos first, then alphabetically
        let trainers = response.trainers
            .sorted { lhs, rhs in
                let lhasPhoto = lhs.photoURL != nil && !(lhs.photoURL?.isEmpty ?? true)
                let rhasPhoto = rhs.photoURL != nil && !(rhs.photoURL?.isEmpty ?? true)
                if lhasPhoto != rhasPhoto { return lhasPhoto }
                return lhs.displayName < rhs.displayName
            }
            .map { CMSTrainerMapper.toDomain($0) }

        guard !query.isEmpty else { return trainers }
        let normalized = query.lowercased()
        return trainers.filter { $0.displayName.lowercased().contains(normalized) }
    }

    func findByInviteCode(_ code: String) async throws -> PersonalTrainer? {
        // CMS doesn't have a dedicated invite code endpoint yet.
        // Fetch all trainers and filter locally as a fallback.
        let response = try await service.fetchTrainers(limit: 100, offset: 0)
        return response.trainers
            .first { $0.inviteCode?.uppercased() == code.uppercased() }
            .map { CMSTrainerMapper.toDomain($0) }
    }
}

//
//  CMSTrainerModels.swift
//  FitToday
//
//  DTOs for CMS Trainer & Program API integration.
//  Supports: /api/trainers, /api/trainers/[id], /api/trainers/[id]/reviews,
//            /api/trainers/count, /api/programs, /api/programs/[id]
//

import Foundation

// MARK: - Trainer List Response

struct CMSTrainerListResponse: Codable, Sendable {
    let trainers: [CMSTrainer]
    let total: Int?
    let limit: Int?
    let offset: Int?
}

// MARK: - Trainer Count Response

struct CMSTrainerCountResponse: Codable, Sendable {
    let count: Int
}

// MARK: - CMS Trainer Profile (nested object in API response)

struct CMSTrainerProfile: Codable, Sendable {
    let bio: String?
    let specializations: [String]?
    let city: String?
    let maxStudents: Int?
}

// MARK: - CMS Trainer DTO

struct CMSTrainer: Codable, Sendable, Identifiable {
    let id: String
    let displayName: String
    let email: String?
    let photoURL: String?
    let profile: CMSTrainerProfile?
    let isActive: Bool?
    let inviteCode: String?
    let currentStudentCount: Int?
    let rating: Double?
    let reviewCount: Int?
    let createdAt: Date?

    // Convenience accessors for nested profile fields
    var bio: String? { profile?.bio }
    var specializations: [String] { profile?.specializations ?? [] }
    var city: String? { profile?.city }
    var maxStudents: Int? { profile?.maxStudents }
}

// MARK: - Trainer Review List Response

struct CMSTrainerReviewListResponse: Codable, Sendable {
    let reviews: [CMSTrainerReview]
    let total: Int?
    let limit: Int?
    let offset: Int?
}

// MARK: - CMS Trainer Review DTO

struct CMSTrainerReview: Codable, Sendable, Identifiable {
    let id: String
    let trainerId: String
    let studentId: String
    let studentName: String?
    let rating: Int
    let comment: String?
    let createdAt: Date?
}

// MARK: - Connection Request

struct CMSConnectionRequest: Codable, Sendable {
    let studentId: String
    let studentName: String
}

// MARK: - Connection Response

struct CMSConnectionResponse: Codable, Sendable {
    let id: String
    let trainerId: String
    let studentId: String
    let status: String
    let createdAt: Date?
}

// MARK: - Connection Status Response

struct CMSConnectionStatusResponse: Codable, Sendable {
    let connected: Bool
    let status: String?
    let relationshipId: String?
    let connectedAt: Date?
}

// MARK: - Create Review Request

struct CMSCreateReviewRequest: Codable, Sendable {
    let studentId: String
    let studentName: String
    let rating: Int
    let comment: String?
}

// MARK: - Program List Response

struct CMSProgramListResponse: Codable, Sendable {
    let programs: [CMSProgram]
    let total: Int?
    let limit: Int?
}

// MARK: - CMS Program DTO

struct CMSProgram: Codable, Sendable, Identifiable {
    let id: String
    let trainerId: String
    let title: String
    let description: String?
    let category: String?
    let durationWeeks: Int?
    let difficulty: String?
    let imageUrl: String?
    let isPublished: Bool?
    let workoutCount: Int?
    let createdAt: Date?
    let updatedAt: Date?
}

// MARK: - User Profile Response

struct CMSUserProfileResponse: Codable, Sendable {
    let uid: String
    let role: String?
    let displayName: String?
}

//
//  CMSTrainerMapper.swift
//  FitToday
//
//  Maps CMS trainer DTOs to domain models.
//

import Foundation

enum CMSTrainerMapper {

    static func toDomain(_ dto: CMSTrainer) -> PersonalTrainer {
        PersonalTrainer(
            id: dto.id,
            displayName: dto.displayName,
            email: dto.email ?? "",
            photoURL: dto.photoURL.flatMap { URL(string: $0) },
            specializations: dto.specializations,
            bio: dto.bio,
            isActive: dto.isActive ?? true,
            inviteCode: dto.inviteCode,
            maxStudents: dto.maxStudents ?? 30,
            currentStudentCount: dto.currentStudentCount ?? 0,
            rating: dto.rating,
            reviewCount: dto.reviewCount
        )
    }
}

